// ─────────────────────────────────────────────────────
//  CONSTANTE DE ANIMAÇÃO
// ─────────────────────────────────────────────────────
/** Frames de game loop entre cada troca de frame de animação */
export const ANIM_SPEED_RUN = 8;    // zumbi corredor: troca a cada 8 frames (~133ms)
export const ANIM_SPEED_GAS = 15;   // gás: troca a cada 15 frames (~250ms)
 
// ─────────────────────────────────────────────────────
//  SELETORES
// ─────────────────────────────────────────────────────
import type { RoadObstacleType, RoadItemType } from './types';
 
/** Retorna o sprite da moto baseado no estado atual */
export function getMotoSprite(state: {
  punching: boolean;
  jumping: boolean;
  turboActive: boolean;
  shieldActive: boolean;
}): string {
  if (state.jumping)      return SPRITE_MOTO_JUMP;
  if (state.punching)     return SPRITE_MOTO_PUNCH;
  if (state.shieldActive) return SPRITE_MOTO_SHIELD;
  if (state.turboActive)  return SPRITE_MOTO_TURBO;
  return SPRITE_MOTO_IDLE;
}
 
/**
 * Retorna o sprite do obstáculo por tipo, com suporte a animação.
 *
 * @param type  - tipo do obstáculo
 * @param frame - frame atual do game loop (pra calcular ciclo de animação)
 * @param hit   - true se o obstáculo já foi atingido (mostra frame de hit)
 */
export function getObstacleSprite(type: RoadObstacleType, frame: number = 0, hit: boolean = false): string {
  switch (type) {
    case 'zumbi':
      return SPRITE_OBS_ZUMBI;
 
    case 'carro':
      return SPRITE_OBS_CARRO;
 
    case 'buraco':
      return SPRITE_OBS_BURACO;
 
    case 'barreira':
      return SPRITE_OBS_BARREIRA;
 
    case 'zumbi_corredor': {
      // Se levou hit → mostra frame de hit
      if (hit) {
        return SPRITE_OBS_ZUMBI_CORREDOR_HIT || SPRITE_OBS_ZUMBI_CORREDOR_RUN1;
      }
      // Ciclo de corrida: alterna entre os frames
      const runIdx = Math.floor(frame / ANIM_SPEED_RUN) % ZUMBI_CORREDOR_RUN_FRAMES.length;
      const runSprite = ZUMBI_CORREDOR_RUN_FRAMES[runIdx];
      // Se os frames de animação estão vazios, retorna o primeiro que tiver
      return runSprite || SPRITE_OBS_ZUMBI_CORREDOR_RUN1;
    }
 
    case 'gas': {
      // Ciclo de pulsação do gás
      const gasIdx = Math.floor(frame / ANIM_SPEED_GAS) % GAS_FRAMES.length;
      const gasSprite = GAS_FRAMES[gasIdx];
      return gasSprite || SPRITE_OBS_GAS_1;
    }
 
    default:
      return SPRITE_OBS_ZUMBI;
  }
}
 
/** Retorna o sprite do item por tipo */
export function getItemSprite(type: RoadItemType): string {
  switch (type) {
    case 'burger': return SPRITE_ITEM_BURGER;
    case 'turbo':  return SPRITE_ITEM_TURBO;
    case 'escudo': return SPRITE_ITEM_ESCUDO;
    default:       return SPRITE_ITEM_BURGER;
  }
}
 
// ─────────────────────────────────────────────────────
//  PRELOADER
// ─────────────────────────────────────────────────────
const imageCache = new Map<string, HTMLImageElement>();
 
function loadImage(src: string): Promise<HTMLImageElement> {
  if (!src) return Promise.resolve(new Image());
  const cached = imageCache.get(src);
  if (cached) return Promise.resolve(cached);
 
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => { imageCache.set(src, img); resolve(img); };
    img.onerror = reject;
    img.src = src;
  });
}
 
export function getCachedImage(src: string): HTMLImageElement | null {
  return imageCache.get(src) ?? null;
}
 
export async function preloadMotoSprites(): Promise<void> {
  const allSprites = [
    // Moto
    SPRITE_MOTO_IDLE, SPRITE_MOTO_PUNCH, SPRITE_MOTO_JUMP,
    SPRITE_MOTO_TURBO, SPRITE_MOTO_SHIELD,
    // Obstáculos estáticos
    SPRITE_OBS_ZUMBI, SPRITE_OBS_CARRO, SPRITE_OBS_BURACO, SPRITE_OBS_BARREIRA,
    // Zumbi corredor (4 frames)
    SPRITE_OBS_ZUMBI_CORREDOR_RUN1, SPRITE_OBS_ZUMBI_CORREDOR_RUN2,
    SPRITE_OBS_ZUMBI_CORREDOR_RUN3, SPRITE_OBS_ZUMBI_CORREDOR_HIT,
    // Gás (3 frames)
    SPRITE_OBS_GAS_1, SPRITE_OBS_GAS_2, SPRITE_OBS_GAS_3,
    // Itens
    SPRITE_ITEM_BURGER, SPRITE_ITEM_TURBO, SPRITE_ITEM_ESCUDO,
  ].filter(s => s.length > 0);
 
  await Promise.all(allSprites.map(loadImage));
}